+
+    procedure UpdateServiceOrderStatus(var ServItemLine: Record "Service Item Line"; Deleting: Boolean)
+    var
+        ServItemLine2: Record "Service Item Line";
+        ServHeader: Record "Service Header";
+        RepairStatus: Record "Repair Status";
+        RepairStatus2: Record "Repair Status";
+        NewStatus: Enum "Service Document Status";
+        RepairStatusPriority: Option;
+        HighestPriorityLineNo: Integer;
+        StatusFound: Boolean;
+    begin
+        if not ServHeader.Get(ServItemLine."Document Type", ServItemLine."Document No.") then
+            exit;
+
+        StatusFound := false;
+        if not Deleting then
+            if ServItemLine."Repair Status Code" <> '' then begin
+                RepairStatus.Get(ServItemLine."Repair Status Code");
+                RepairStatusPriority := RepairStatus.Priority;
+                NewStatus := RepairStatus."Service Order Status";
+                HighestPriorityLineNo := ServItemLine."Line No.";
+                StatusFound := true;
+            end;
+
+        ServItemLine2.Reset();
+        ServItemLine2.SetRange("Document Type", ServItemLine."Document Type");
+        ServItemLine2.SetRange("Document No.", ServItemLine."Document No.");
+        ServItemLine2.SetFilter("Line No.", '<>%1', ServItemLine."Line No.");
+        ServItemLine2.SetFilter("Repair Status Code", '<>%1', '');
+        if ServItemLine2.Find('-') then
+            repeat
+                RepairStatus2.Get(ServItemLine2."Repair Status Code");
+                if not StatusFound then begin
+                    RepairStatusPriority := RepairStatus2.Priority;
+                    NewStatus := RepairStatus2."Service Order Status";
+                    HighestPriorityLineNo := ServItemLine2."Line No.";
+                    StatusFound := true;
+                end else
+                    if RepairStatus2.Priority < RepairStatusPriority then begin
+                        RepairStatusPriority := RepairStatus2.Priority;
+                        NewStatus := RepairStatus2."Service Order Status";
+                        HighestPriorityLineNo := ServItemLine2."Line No.";
+                    end;
+            until ServItemLine2.Next() = 0;
+
+        if StatusFound then
+            if ServHeader.Status <> NewStatus then begin
+                ServHeader.SetValidatingFromLines(true);
+                ServHeader.Validate(Status, NewStatus);
+                if not (ServHeader.Status = ServHeader.Status::Finished) then begin
+                    ServHeader."Finishing Date" := 0D;
+                    ServHeader."Finishing Time" := 0T;
+                    ServHeader."Service Time (Hours)" := 0;
+                end;
+                ServHeader.Modify();
+            end;
+    end;
